1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
13	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const CURSE_SURCHARGE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT = 0.2;
21	const LOYALTY_YEARS_THRESHOLD = 2;
22	const FOLLOWUP_DISCOUNT = 0.15;
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_INSURANCE_VALUE = 250;
27	
28	type Tariff = { base: number; insurance: number };
29	
30	const MAIN_ITEM_TARIFF: Record<string, Tariff> = {
31	  sword: { base: 100, insurance: 1000 },
32	  amulet: { base: 60, insurance: 600 },
33	};
34	
35	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_TARIFF;
36	
37	const itemInsuranceValue = (item: Item): number =>
38	  MAIN_ITEM_TARIFF[item.type]?.insurance ?? COMPONENT_INSURANCE_VALUE;
39	
40	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
41	
42	const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
43	  items.reduce((sum, item) => sum + valueOf(item), 0);
44	
45	const rateAmount = (base: number, applies: boolean, rate: number): number =>
46	  applies ? base * rate : 0;
47	
48	const enchantmentLevel = (item: Item | undefined): number => item?.enchantment ?? 0;
49	
50	const isHighlyEnchanted = (item: Item): boolean =>
51	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
52	
53	const mainItemBase = (item: Item): number => MAIN_ITEM_TARIFF[item.type].base;
54	
55	const mainItemSurcharges = (item: Item): number => {
56	  const base = mainItemBase(item);
57	  return (
58	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
59	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE)
60	  );
61	};
62	
63	const componentGroupBase = (count: number): number => {
64	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
65	  const leftover = count % COMPONENT_BLOCK_SIZE;
66	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
67	};
68	
69	const componentCountsByType = (components: Item[]): Map<string, number> => {
70	  const counts = new Map<string, number>();
71	  for (const item of components) {
72	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
73	  }
74	  return counts;
75	};
76	
77	const sumComponentGroupBases = (components: Item[]): number =>
78	  sumBy([...componentCountsByType(components).values()], componentGroupBase);
79	
80	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
81	  const mainItems: Item[] = [];
82	  const components: Item[] = [];
83	  for (const item of items) {
84	    (isMainItem(item) ? mainItems : components).push(item);
85	  }
86	  return { mainItems, components };
87	};
88	
89	const sumMainItemBases = (mainItems: Item[]): number => sumBy(mainItems, mainItemBase);
90	
91	const sumMainItemSurcharges = (mainItems: Item[]): number => sumBy(mainItems, mainItemSurcharges);
92	
93	const isLoyalCustomer = (customer: Customer): boolean =>
94	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
95	
96	const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
97	  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
98	  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
99	
100	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
101	  const { mainItems, components } = partitionItems(step.items);
102	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
103	  const surcharges = sumMainItemSurcharges(mainItems);
104	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
105	  const discounts = totalDiscount(policyBase, customer, isFollowUp);
106	  return {
107	    premium: ceilWithEpsilon(policyBase + surcharges + firstInsurance - discounts + PROCESSING_FEE),
108	  };
109	};
110	
111	const countQuotesBefore = (steps: Step[], index: number): number =>
112	  steps.slice(0, index).filter((s) => s.op === "quote").length;
113	
114	const insuranceSumOf = (step: QuoteStep): number => sumBy(step.items, itemInsuranceValue);
115	
116	const findInsuredItem = (policyStep: QuoteStep, itemType: string): Item | undefined =>
117	  policyStep.items.find((item) => item.type === itemType);
118	
119	const reimbursementRate = (item: Item | undefined): number =>
120	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
121	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
122	    : 1;
123	
124	const damagePayout = (damage: Damage, policyStep: QuoteStep): number => {
125	  const item = findInsuredItem(policyStep, damage.itemType);
126	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
127	};
128	
129	const totalPayout = (damages: Damage[], policyStep: QuoteStep): number =>
130	  sumBy(damages, (d) => damagePayout(d, policyStep));
131	
132	const processClaim = (
133	  step: ClaimStep,
134	  steps: Step[],
135	  remainingCaps: Map<number, number>,
136	): { payout: number; remainingCap: number } => {
137	  const policyStep = steps[step.policy] as QuoteStep;
138	  const cap = remainingCaps.get(step.policy) ?? CAP_MULTIPLIER * insuranceSumOf(policyStep);
139	  const desired = totalPayout(step.incident.damages, policyStep);
140	  const payout = Math.min(desired, cap);
141	  const remainingCap = cap - payout;
142	  remainingCaps.set(step.policy, remainingCap);
143	  return { payout, remainingCap };
144	};
145	
146	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
147	  const remainingCaps = new Map<number, number>();
148	  return {
149	    results: scenario.steps.map((step, i) =>
150	      step.op === "quote"
151	        ? priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0)
152	        : processClaim(step, scenario.steps, remainingCaps),
153	    ),
154	  };
155	};
